module top(y, clk, a, b, c, d, e);
  output wire y;
  input wire clk;
  input wire signed [18:0] a;
  input wire [13:0] b;
  input wire signed [15:0] c;
  input wire [8:0] d;
  input wire [10:0] e;
  reg r = 0;

  assign y = b[3:2] ? r : 0;
  always @(posedge clk)
    r <= d ? b & ((b ? a : c) && {d, b})
      : (a > ((e ? b : 1) ? e
        : d));
endmodule

